const response = await fetch(url, {
method: "POST",
headers: {
"Content-Type": "application/json",
Authorization: `Bearer ${apiKey}`,
"X-Hookdeck-Source-Name": sourceName,
...headers,
},
body: JSON.stringify({ data }),
